// src/redux/store.ts
import { legacy_createStore as createStore, compose, Store } from "redux";
import { rootReducer, initialState } from "./reducers";
import { loadFromLocalStorage, saveToLocalStorage } from "@/lib/helper/storageLocal";

export type RootState = typeof initialState;
type StateKey = keyof RootState;

export const persistKeys: StateKey[] = ["notifications", "sidebar", "todo", "theme"];

const isBrowser = typeof window !== "undefined";
let persistTimeout: ReturnType<typeof setTimeout> | null = null;

/**
 * Helper to safely assign state values
 */
export function assignStateValue<K extends keyof RootState>(
  state: RootState,
  key: K,
  value: RootState[K]
) {
  state[key] = value;
}

/**
 * Load persisted slices (client only)
 */
const loadInitialState = (): RootState => {
  if (!isBrowser) return initialState;

  const loaded: RootState = { ...initialState };

  persistKeys.forEach((key) => {
    const saved = loadFromLocalStorage<RootState[typeof key]>(key);
    if (saved !== undefined) {
      assignStateValue(loaded, key, saved as RootState[typeof key]);
    }
  });

  return loaded;
};

/**
 * Persist updated slices
 */
const savePersistedState = (store: Store<RootState>) => {
  const state = store.getState();
  persistKeys.forEach((key) => saveToLocalStorage(state[key], key));
};

const schedulePersistedStateSave = (store: Store<RootState>) => {
  if (!isBrowser) return;

  if (persistTimeout) {
    clearTimeout(persistTimeout);
  }

  persistTimeout = setTimeout(() => {
    savePersistedState(store);
    persistTimeout = null;
  }, 120);
};

declare global {
  interface Window {
    __REDUX_DEVTOOLS_EXTENSION_COMPOSE__?: typeof compose;
  }
}

const composeEnhancers =
  (isBrowser && window.__REDUX_DEVTOOLS_EXTENSION_COMPOSE__) || compose;

let _store: Store<RootState> | undefined;

function getStoreSingleton(): Store<RootState> {
  if (_store) return _store;

  const preloadedState = loadInitialState();
  const store = createStore(rootReducer, preloadedState, composeEnhancers());
  if (isBrowser) store.subscribe(() => schedulePersistedStateSave(store));

  _store = store;
  return store;
}

export const store = getStoreSingleton();

import {
  createConnector,
  createDispatch,
  createStateSelector,
  createStateSelectorHook,
} from "react-redux-methods";

import {actions, selectors} from "./reducers";
import { store } from "./store";



export const reduxConnector = createConnector( selectors, actions );
export const dispatch = createDispatch( store.dispatch, actions );
export const getState= createStateSelector( store, selectors );
export const useGetState= createStateSelectorHook( selectors );

"use client";

import React, { useEffect, useState } from "react";
import { Provider } from "react-redux";
import { persistKeys, store } from "@/redux/store";
import { loadFromLocalStorage } from "@/lib/helper/storageLocal";
import type { RootState } from "@/redux/store";

// ✅ generic helper to assign values type-safely by key
function assignPersistedValue<K extends keyof RootState>(
  target: Partial<RootState>,
  key: K,
  value: RootState[K]
) {
  target[key] = value;
}

export default function StoreProvider({
  children,
}: {
  children: React.ReactNode;
}) {
  const [ready, setReady] = useState(false);

  useEffect(() => {
    const persisted: Partial<RootState> = {};

    persistKeys.forEach((key) => {
      const value = loadFromLocalStorage<RootState[typeof key]>(key);
      if (value !== undefined) {
        // ✅ type-safe assignment with helper
        assignPersistedValue(persisted, key, value);
      }
    });

    // Dispatch a rehydration event to Redux store
    store.dispatch({
      type: "__REHYDRATE__",
      payload: persisted,
    });

    // Prevent hydration mismatch (Next.js SSR safety)
    requestAnimationFrame(() => setReady(true));
  }, []);

  if (!ready) {
    return <div suppressHydrationWarning />;
  }

  return <Provider store={store}>{children}</Provider>;
}

import { combineReducers } from "redux";

import {
  notificationsReducer,
  notificationsActions,
  notificationsSelectors,
  notifacationState,

} from "./notification";

import { SidebarActions, sidebarReducer, sidebarSelectors, sidebarState } from "./sidebar";
import { todoActions, todoReducer, todoSelectors, todoState } from "./todo";
import { themeReducer, themeActions, themeSelectors, themeState } from "./theme";

export const rootReducer = combineReducers({
  notifications: notificationsReducer, // <--- key should match 'selectionNode' value
  sidebar: sidebarReducer,
  todo: todoReducer,
  theme: themeReducer,
});

export const actions = {
  ...notificationsActions,
  ...SidebarActions,
  ...todoActions,
  ...themeActions,
};

export const selectors = {
  ...notificationsSelectors,
  ...sidebarSelectors,
  ...todoSelectors,
  ...themeSelectors,
};


export const initialState = {
  notifications: notifacationState, // <--- key should match 'selectionNode' value
  sidebar: sidebarState,
  todo: todoState,
  theme: themeState,
};

import { createReduxMethods, ComposePayload } from 'react-redux-methods';

export type INotification = {
  isOpen: boolean;
  message: string;
}

export const notifacationState: INotification = {
  isOpen: false,
  message: 'Hello',
};

const [notificationsReducer, notificationsActions, notificationsSelectors] = createReduxMethods({
  initialState: notifacationState,
  reducers: {
    setNotificationShow: (state, action) => ({
      ...state,
      isOpen: true,
      message: action.payload,
    }),
    setNotificationHide: () => notifacationState,
   
    updateNotification: (s, a: ComposePayload<string>) => ({
      ...s,
      message: a.payload,
    }),
  },
  selectionNode: 'notifications', 
  selectors: {
    getNotificationStatus: (s) => s.isOpen,
    getNotificationMessage: (s) => s.message || "", 
  },
});

// export all
export { notificationsReducer, notificationsActions, notificationsSelectors };

import { createReduxMethods } from "react-redux-methods";



export type SidebarStateProps = {
  isOpen: boolean;
};

export const sidebarState: SidebarStateProps = {
  isOpen: true,
};

const [sidebarReducer, SidebarActions, sidebarSelectors] = createReduxMethods({
  initialState: sidebarState,
  reducers: {
    setSidebarHide: (state) => ({
      ...state,
      isOpen: false,
    }),
    setSidebarShow: () => sidebarState,
  },
  selectionNode: "sidebar",
  selectors: {
    getSidebarStatus: (s) => s.isOpen,
  },
});

// export all
export { sidebarReducer, SidebarActions, sidebarSelectors };

import { createReduxMethods, ComposePayload } from "react-redux-methods";

/* ================== TYPES ================== */
export type ITodoItem = {
  id: string;
  text: string;
  completed: boolean;
};

export type ITodoState = {
  items: ITodoItem[];
};

/* ================== INITIAL STATE ================== */
export const todoState: ITodoState = {
  items: [],
};

/* ================== REDUX METHODS ================== */
const [todoReducer, todoActions, todoSelectors] = createReduxMethods({
  initialState: todoState,

  reducers: {
    addTodo: (state, action: ComposePayload<string>) => ({
      ...state,
      items: [
        ...state.items,
        {
          id: crypto.randomUUID(),
          text: action.payload,
          completed: false, // ✅ default
        },
      ],
    }),

    toggleTodo: (state, action: ComposePayload<string>) => ({
      ...state,
      items: state.items.map((t) =>
        t.id === action.payload
          ? { ...t, completed: !t.completed }
          : t
      ),
    }),

    deleteTodo: (state, action: ComposePayload<string>) => ({
      ...state,
      items: state.items.filter((t) => t.id !== action.payload),
    }),

    clearTodos: () => todoState,
  },

  selectionNode: "todo",

  selectors: {
    getTodos: (s) => s.items,
    getTodoCount: (s) => s.items.length,
    getCompletedCount: (s) => s.items.filter((t) => t.completed).length,
  },
});

export { todoReducer, todoActions, todoSelectors };

import { createReduxMethods, ComposePayload } from "react-redux-methods";
import type { ThemeState, ThemePresetId, ThemeCssVar, ThemeCustomOverrides } from "@/lib/theme/types";

/**
 * Theme Redux Slice - manages all theme state
 * Includes: active preset, custom color overrides, radius, builder open state
 */

export const themeState: ThemeState = {
  activePreset: "default",
  customLight: {},
  customDark: {},
  radius: 0.625,
  isBuilderOpen: false,
};

const [themeReducer, themeActions, themeSelectors] = createReduxMethods({
  initialState: themeState,
  reducers: {
    /**
     * Switch to a different preset theme
     * Also clears all custom overrides for a clean slate
     */
    setThemePreset: (state, action: ComposePayload<ThemePresetId>) => ({
      ...state,
      activePreset: action.payload,
      customLight: {},
      customDark: {},
    }),

    /**
     * Override a single CSS variable in light mode
     */
    setCustomLight: (
      state,
      action: ComposePayload<{ key: ThemeCssVar; value: string }>
    ) => ({
      ...state,
      customLight: {
        ...state.customLight,
        [action.payload.key]: action.payload.value,
      },
    }),

    /**
     * Override a single CSS variable in dark mode
     */
    setCustomDark: (
      state,
      action: ComposePayload<{ key: ThemeCssVar; value: string }>
    ) => ({
      ...state,
      customDark: {
        ...state.customDark,
        [action.payload.key]: action.payload.value,
      },
    }),

    /**
     * Remove a single light-mode override and fall back to the active preset/default token
     */
    clearCustomLight: (state, action: ComposePayload<ThemeCssVar>) => {
      const nextCustomLight = { ...state.customLight };
      delete nextCustomLight[action.payload];

      return {
        ...state,
        customLight: nextCustomLight,
      };
    },

    /**
     * Remove a single dark-mode override and fall back to the active preset/default token
     */
    clearCustomDark: (state, action: ComposePayload<ThemeCssVar>) => {
      const nextCustomDark = { ...state.customDark };
      delete nextCustomDark[action.payload];

      return {
        ...state,
        customDark: nextCustomDark,
      };
    },

    /**
     * Batch import theme overrides from JSON
     * Replaces customLight, customDark, and radius entirely
     */
    importThemeOverrides: (
      state,
      action: ComposePayload<{
        preset: ThemePresetId;
        customLight: ThemeCustomOverrides;
        customDark: ThemeCustomOverrides;
        radius: number;
      }>
    ) => ({
      ...state,
      activePreset: action.payload.preset,
      customLight: action.payload.customLight,
      customDark: action.payload.customDark,
      radius: action.payload.radius,
    }),

    /**
     * Update the border radius value
     */
    setRadius: (state, action: ComposePayload<number>) => ({
      ...state,
      radius: action.payload,
    }),

    /**
     * Open or close the theme builder panel
     */
    setThemeBuilderOpen: (state, action: ComposePayload<boolean>) => ({
      ...state,
      isBuilderOpen: action.payload,
    }),

    /**
     * Reset all theme state to defaults
     */
    resetTheme: () => ({
      ...themeState,
      isBuilderOpen: false,
    }),
  },
  selectionNode: "theme",
  selectors: {
    getActivePreset: (s) => s.activePreset,
    getCustomLight: (s) => s.customLight,
    getCustomDark: (s) => s.customDark,
    getRadius: (s) => s.radius,
    getThemeBuilderOpen: (s) => s.isBuilderOpen,
  },
});

export { themeReducer, themeActions, themeSelectors };

/**
 * Theme System TypeScript Types
 * Canonical source for theme type definitions
 */

/**
 * All CSS custom property names managed by the theme system
 */
export type ThemeCssVar =
  | "--background"
  | "--foreground"
  | "--card"
  | "--card-foreground"
  | "--popover"
  | "--popover-foreground"
  | "--primary"
  | "--primary-foreground"
  | "--secondary"
  | "--secondary-foreground"
  | "--muted"
  | "--muted-foreground"
  | "--accent"
  | "--accent-foreground"
  | "--destructive"
  | "--border"
  | "--input"
  | "--ring"
  | "--chart-1"
  | "--chart-2"
  | "--chart-3"
  | "--chart-4"
  | "--chart-5"
  | "--sidebar"
  | "--sidebar-foreground"
  | "--sidebar-primary"
  | "--sidebar-primary-foreground"
  | "--sidebar-accent"
  | "--sidebar-accent-foreground"
  | "--sidebar-border"
  | "--sidebar-ring";

/**
 * A complete mapping of all CSS variables for a single mode (light or dark)
 * Values are oklch() strings
 */
export type ThemeTokenMap = Record<ThemeCssVar, string>;

/**
 * User customizations on top of a preset theme
 */
export type ThemeCustomOverrides = Partial<ThemeTokenMap>;

/**
 * One complete theme preset with both light and dark variants
 */
export type ThemePreset = {
  id: ThemePresetId;
  label: string;
  description: string;
  /** Accent color swatch for the preset card - light mode */
  accentLight: string;
  /** Accent color swatch for the preset card - dark mode */
  accentDark: string;
  light: ThemeTokenMap;
  dark: ThemeTokenMap;
};

/**
 * The unique identifiers for all available theme presets
 */
export type ThemePresetId =
  | "default"
  | "midnight"
  | "forest"
  | "ocean"
  | "sunset"
  | "nordic"
  | "rosewood"
  | "lavender"
  | "graphite"
  | "aurora"
  | "copper"
  | "jade";

/**
 * Redux state shape for theme slice
 */
export type ThemeState = {
  /** Active theme preset identifier */
  activePreset: ThemePresetId;
  /** User color overrides for light mode (merged on top of preset) */
  customLight: ThemeCustomOverrides;
  /** User color overrides for dark mode (merged on top of preset) */
  customDark: ThemeCustomOverrides;
  /** Border radius in rem (e.g., 0.625) */
  radius: number;
  /** Whether the theme builder sheet is open */
  isBuilderOpen: boolean;
};

/**
 * Components of an OKLCH color for conversion utilities
 */
export type OklchComponents = {
  /** Lightness (0–1) */
  l: number;
  /** Chroma (0–0.4 typical) */
  c: number;
  /** Hue (0–360) */
  h: number;
  /** Alpha (0–1), optional */
  alpha?: number;
};

/**
 * Exported theme as JSON (for sharing/importing)
 */
export type ThemeExportJSON = {
  version: 1;
  activePreset: ThemePresetId;
  customLight: ThemeCustomOverrides;
  customDark: ThemeCustomOverrides;
  radius: number;
};

/**
 * Theme panel tabs — "export" was removed from the panel UI.
 * ExportPanel.tsx is still available as a standalone component for custom usage.
 */
export type ThemeBuilderTab = "presets" | "colors" | "radius";

/** Used by ExportPanel when mounted independently */
export type ExportFormat = "css" | "json";

export function loadFromLocalStorage<T>(
  key: string,
  validate?: (value: unknown) => value is T
): T | undefined {
  // Guard server-side usage where localStorage is unavailable.
  if (typeof window === "undefined" || typeof localStorage === "undefined") {
    return undefined;
  }

  let item: string | null;
  try {
    item = localStorage.getItem(key);
  } catch {
    return undefined;
  }

  if (!item) {
    return undefined;
  }

  let parsed: unknown;
  try {
    parsed = JSON.parse(item) as unknown;
  } catch {
    return undefined;
  }

  if (validate && !validate(parsed)) {
    return undefined;
  }

  return parsed as T;
}

export function saveToLocalStorage<T>(data: T, key: string): void {
  // Guard server-side usage where localStorage is unavailable.
  if (typeof window === "undefined" || typeof localStorage === "undefined") {
    return;
  }

  try {
    localStorage.setItem(key, JSON.stringify(data));
  } catch (error) {
    console.error("Error saving to localStorage:", key, error);
  }
}
